    <div className="test-card">
      <h2>{type}</h2>
      <img src={`/images/types/${type}.png`} alt={type} style={{ maxWidth: "200px" }} />
      <p>ეს არის მოკლე აღწერა თქვენს ფსიქოტიპზე.</p>
      <p>
        მეტი ინფორმაციისთვის გადადით{" "}
        <a href="/articles">მიმოხილვების</a> გვერდზე
      </p>
    </div>
  );
}
